=={{
(function() {
  const b = $json.body;
  const base = {
    customer: {
      tax_id: b.tax_id,
      name: b.name,
      email: b.email,
      phone: b.phone,
      address: {
        zip_code: b.zip_code,
        street: b.street,
        number: b.number,
        neighborhood: b.neighborhood,
        city: b.city,
        state: b.state
      }
    },
    product_id: b.product_id,
    whatsapp: b.phone,
    operator_id: b.operator_id || ""
  };
  if (b.tipo_cliente === "PF") {
    base.custom_fields = {
      "4ac62ade-98c2-4b2f-81da-5cfddc5b91b9": b.payment_day_type,
      "8dcae81b-1947-47de-b2e2-184de8187414": b.payment_day,
      "4b55d2b1-b5c6-4b36-a452-59c77092a954": b.bank
    };
  } else {
    base.custom_fields = {
      "8205e586-38ae-413f-8107-7165375cbd72": b.salary_range || "",
      "1fc8814b-1dd4-4b47-8ae6-61f45c4804f4": b.benefit_number,
      "4b55d2b1-b5c6-4b36-a452-59c77092a954": b.bank
    };
  }
  return base;
})()
}}
